import 'package:firebase_auth/firebase_auth.dart'; import 'package:firebase_database/firebase_database.dart'; import 'package:injectable/injectable.dart'; import '../../../core/constants/app_constants.dart'; @injectable class PresenceBroadcaster { final _db = FirebaseDatabase.instance; Future<void> setOnline(String deviceId) async { final uid = FirebaseAuth.instance.currentUser?.uid; if (uid == null) return; final ref = _db.ref('${AppConstants.presencePath}/$uid/$deviceId'); await ref.update({'online': true, 'ts': ServerValue.timestamp}); await ref.onDisconnect().update({'online': false, 'ts': ServerValue.timestamp}); } Future<void> setOffline(String deviceId) async { final uid = FirebaseAuth.instance.currentUser?.uid; if (uid == null) return; await _db.ref('${AppConstants.presencePath}/$uid/$deviceId').update({'online': false, 'ts': ServerValue.timestamp}); } }